#include <stdio.h>
#include <stdlib.h>

void backtrack(int* nums, int start, int n, int* current, int currentSize, int*** result, int* resultSize) {
    (*resultSize)++;
    (*result) = realloc((*result), (*resultSize) * sizeof(int*));
    (*result)[(*resultSize) - 1] = malloc((currentSize + 1) * sizeof(int));
    for (int i = 0; i < currentSize; i++) {
        (*result)[(*resultSize) - 1][i] = current[i];
    }
    (*result)[(*resultSize) - 1][currentSize] = -1;
    for (int i = start; i < n; i++) {
        if (i > start && nums[i] == nums[i - 1]) continue;
        current[currentSize] = nums[i];
        backtrack(nums, i + 1, n, current, currentSize + 1, result, resultSize);
    }
}

void findSubsetsWithDuplicates(int* inputNumbers, int n) {
    int** result;
    int resultSize = 0;
    result = NULL;
    int* current = malloc(n * sizeof(int));
    qsort(inputNumbers, n, sizeof(int), compare);
    backtrack(inputNumbers, 0, n, current, 0, &result, &resultSize);
    for (int i = 0; i < resultSize; i++) {
        for (int j = 0; j < n; j++) {
            if (result[i][j] == -1) break;
            printf("%d ", result[i][j]);
        }
        printf("\n");
    }
    free(current);
    for (int i = 0; i < resultSize; i++) {
        free(result[i]);
    }
    free(result);
}

int compare(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

