import java.util.Scanner;

public class Main {
    public static void backtrack(int[] nums, int start, ArrayList<Integer> current, ArrayList<ArrayList<Integer>> result) {
        result.add(new ArrayList<>(current));
        for (int i = start; i < nums.length; i++) {
            if (i > start && nums[i] == nums[i - 1]) continue;
            current.add(nums[i]);
            backtrack(nums, i + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    public static ArrayList<ArrayList<Integer>> findSubsetsWithDuplicates(int[] inputNumbers) {
        ArrayList<ArrayList<Integer>> result = new ArrayList<>();
        ArrayList<Integer> current = new ArrayList<>();
        Arrays.sort(inputNumbers);
        backtrack(inputNumbers, 0, current, result);
        return result;
    }
}

